// Normative VP9 probability and scan values used by the bitstream syntax. The
// compact base64 form keeps this standalone implementation small. Values were
// cross-checked byte-for-byte against the BSD-licensed libvpx reference tables;
// no libvpx code or runtime dependency is imported.

const BASE64_ALPHABET = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";

function decodeBase64Bytes(encoded) {
  const normalized = encoded.replace(/\s+/g, "");
  const padding = normalized.endsWith("==") ? 2 : normalized.endsWith("=") ? 1 : 0;
  const output = new Uint8Array((normalized.length * 3 >> 2) - padding);
  let accumulator = 0;
  let accumulatedBits = 0;
  let outputIndex = 0;
  for (const character of normalized) {
    if (character === "=") break;
    const value = BASE64_ALPHABET.indexOf(character);
    if (value < 0) throw new Error("Invalid embedded VP9 base64 table.");
    accumulator = accumulator * 64 + value;
    accumulatedBits += 6;
    if (accumulatedBits >= 8) {
      accumulatedBits -= 8;
      output[outputIndex] = (accumulator >> accumulatedBits) & 0xff;
      outputIndex += 1;
      accumulator &= (1 << accumulatedBits) - 1;
    }
  }
  return output;
}

function decodeBase64Uint16(encoded) {
  const bytes = decodeBase64Bytes(encoded);
  if (bytes.byteLength % 2) throw new Error("Invalid embedded VP9 uint16 table.");
  const values = new Uint16Array(bytes.byteLength / 2);
  for (let index = 0; index < values.length; index += 1) {
    values[index] = bytes[index * 2] | (bytes[index * 2 + 1] << 8);
  }
  return values;
}

