function coefficientProbabilityIndex(planeType, referenceType, band, context, node) {
  const contextOffset = COEFFICIENT_BAND_OFFSETS[band] + context;
  return (((planeType * 2 + referenceType) * 33 + contextOffset) * 3) + node;
}

function keyframeYModeProbabilities(aboveMode, leftMode) {
  const start = (aboveMode * 10 + leftMode) * 9;
  return KEYFRAME_Y_MODE_PROBABILITIES.subarray(start, start + 9);
}

function keyframeUvModeProbabilities(lumaMode) {
  const start = lumaMode * 9;
  return KEYFRAME_UV_MODE_PROBABILITIES.subarray(start, start + 9);
}

function paretoProbabilities(pivotProbability) {
  const start = (pivotProbability - 1) * 8;
  return PARETO_PROBABILITIES.subarray(start, start + 8);
}

function createDefaultCoefficientProbabilities() {
  return DEFAULT_COEFFICIENT_PROBABILITIES.map(probabilities => probabilities.slice());
}

