const SCAN_CACHE = new Map();

function scanOrder(transformSize, transformType) {
  const normalizedTransformType = transformSize === 3 ? 0 : transformType;
  const key = transformSize + ":" + normalizedTransformType;
  let scan = SCAN_CACHE.get(key);
  if (!scan) {
    const encoded = SCAN_DATA[key];
    if (!encoded) throw new Error("Unsupported VP9 transform scan " + key + ".");
    scan = transformSize === 3 ? decodeBase64Uint16(encoded) : decodeBase64Bytes(encoded);
    SCAN_CACHE.set(key, scan);
  }
  return scan;
}

function coefficientNeighbors(scan, transformSize, transformType, coefficientIndex) {
  if (coefficientIndex === 0) return [0, 0];
  const width = 4 << transformSize;
  const rasterIndex = scan[coefficientIndex];
  const hasAbove = rasterIndex >= width;
  const hasLeft = rasterIndex % width !== 0;
  const normalizedTransformType = transformSize === 3 ? 0 : transformType;
  if (normalizedTransformType === 1 && hasLeft) return [rasterIndex - 1, rasterIndex - 1];
  if (normalizedTransformType === 2 && hasAbove) {
    return [rasterIndex - width, rasterIndex - width];
  }
  if (hasAbove && hasLeft) return [rasterIndex - width, rasterIndex - 1];
  const neighbor = hasAbove ? rasterIndex - width : rasterIndex - 1;
  return [neighbor, neighbor];
}

